#include <vector>
#include <algorithm>
#include <cmath>

using namespace std;

typedef long long ll;

// Define the modulus
const ll MOD = 1e9 + 7;

// Modular exponentiation: (base^exp) % mod
ll power(ll base, ll exp) {
    ll res = 1;
    base %= MOD;
    while (exp > 0) {
        if (exp % 2 == 1) res = (res * base) % MOD;
        base = (base * base) % MOD;
        exp /= 2;
    }
    return res;
}

struct Segment {
    ll n1;
    ll n0;
};

// Custom comparator function
// Returns true if segment A should come before segment B (A > B)
bool compareSegments(const Segment& A, const Segment& B) {
    // Rule 1: Prefer more '1's
    if (A.n1 != B.n1) {
        return A.n1 > B.n1;
    }
    // Rule 2: If '1's are equal, prefer fewer '0's (since 0s are less significant than the next 1 block)
    return A.n0 < B.n0;
}

long long solve(std::vector<long long> nums1, std::vector<long long> nums0) {
    int n = nums1.size();
    vector<Segment> segments(n);

    for (int i = 0; i < n; ++i) {
        segments[i] = {nums1[i], nums0[i]};
    }

    // Sort the segments using the custom comparison rule
    sort(segments.begin(), segments.end(), compareSegments);

    ll total_value = 0;

    for (const auto& seg : segments) {
        ll n1 = seg.n1;
        ll n0 = seg.n0;

        // 1. Calculate Value(Segment): 1^n1 0^n0. Value is 2^n1 - 1.
        ll value_segment = 0;
        if (n1 > 0) {
            // (2^n1 - 1) mod MOD
            ll two_pow_n1 = power(2, n1);
            value_segment = (two_pow_n1 - 1 + MOD) % MOD;
        }

        // 2. Calculate Shift Factor: 2^(n1 + n0) mod MOD
        ll length = n1 + n0;
        ll shift_factor = power(2, length);

        // 3. Update total_value: V_new = (V_old * 2^Length) + Value(Segment)

        // V_old * 2^Length mod MOD
        total_value = (total_value * shift_factor) % MOD;

        // + Value(Segment) mod MOD
        total_value = (total_value + value_segment) % MOD;
    }

    return total_value;
}

