#include <cmath>

using namespace std;

typedef long long ll;

const ll MOD = 1e9 + 7;

// Modular exponentiation: (base^exp) % MOD
ll power(ll base, ll exp) {
    ll res = 1;
    base %= MOD;
    while (exp > 0) {
        if (exp % 2 == 1) res = (res * base) % MOD;
        base = (base * base) % MOD;
        exp /= 2;
    }
    return res;
}

struct Segment {
    ll n1; // count of '1's
    ll n0; // count of '0's
};

// Custom comparator for sorting segments
// A precedes B if N_A > N_B OR (N_A == N_B AND Z_A < Z_B)
bool compareSegments(const Segment& a, const Segment& b) {
    if (a.n1 != b.n1) {
        return a.n1 > b.n1; // Primary sort: N1 descending
    }
    return a.n0 < b.n0; // Secondary sort: N0 ascending
}

long long solve(std::vector<long long> nums1, std::vector<long long> nums0) {
    int n = nums1.size();
    vector<Segment> segments;

    for (int i = 0; i < n; ++i) {
        segments.push_back({nums1[i], nums0[i]});
    }

    // Sort the segments according to the greedy criterion
    sort(segments.begin(), segments.end(), compareSegments);

    ll result = 0;

    for (const auto& seg : segments) {
        ll N1 = seg.n1;
        ll N0 = seg.n0;
        ll L = N1 + N0;

        // 1. Calculate V(S_i) = (2^N1 - 1) * 2^N0 mod MOD
        ll V_Si;
        if (N1 == 0) {
            // Segment is 0^N0, value is 0
            V_Si = 0;
        } else {
            // 2^N1 - 1 mod MOD
            // power(2, N1) returns 2^N1 mod MOD. We need to subtract 1, handling potential negative result.
            ll term1 = (power(2, N1) - 1 + MOD) % MOD;

            // 2^N0 mod MOD
            ll term2 = power(2, N0);

            V_Si = (term1 * term2) % MOD;
        }

        // 2. Calculate 2^L mod MOD
        ll P_L = power(2, L);

        // 3. Update result: R_new = (R_old * 2^L + V(S_i)) mod MOD
        ll term_shift = (result * P_L) % MOD;
        result = (term_shift + V_Si) % MOD;
    }

    return result;
}

